import React from "react"

class Evalulation extends React.Component {
    constructor(props) {
        super(props);
        this.state = {
            results: []
        };
    }


        componentDidMount() {


          const search = this.props.location.search;
          const params = new URLSearchParams(search);
          const day = params.get('day');
          const month = params.get('month');


          //console.log(day)
          //console.log(month)

          var query = ""
          if (day != null && month != null) {
            query = "?day=" + day + "&month=" + month
          }

            let headers = new Headers();

            headers.append('Content-Type', 'application/json');
            headers.append('Accept', 'application/json');

            //headers.append('Access-Control-Allow-Origin', 'http://localhost:3000');
            //headers.append('Access-Control-Allow-Credentials', 'true');

            fetch(`http://localhost:9000/amioncall`+query, {
                "method": "GET",
                headers: headers
              })
              .then(response => response.json())
              .then(response => {
                //console.log(response);
                this.setState({results: response})
                //_forEach(response, d => console.log(d.name))
                //console.log(this.state.results)
              })
              .catch(err => {
                console.log(err);
              });


          }

          render() {


            var todayDate = "Loading ..."
            var teamHtml = ""

            var content = []
                for (var x in this.state.results.team) {

                      //console.log(this.state.results[x])
                      todayDate = "Date: " + this.state.results.team[x].date

                      var color = "black"
                      if (this.state.results.team[x].turnover) {
                        color = "red"
                      }

                      teamHtml = <div style={{marginBottom: '10px', color: color}}><b>{this.state.results.team[x].assignment }: <u>{this.state.results.team[x].name} * medHubID: ({this.state.results.team[x].userID})</u></b></div>


                      var residentsContent = []
                      for (var y in this.state.results.team[x].members) {

                        /*
                        fetch(`https://applet-test.ucsf.edu/residencyAPIs/findid?name=` + this.state.results[x].residents[y].name, {
                          "method": "GET"
                        })
                        .then(response => response.json())
                        .then(response => {
                          console.log(response);
                          //this.setState({results: response})
                          //_forEach(response, d => console.log(d.name))
                          //console.log(this.state.results)
                          residentsContent.push(<div style={{marginLeft: '10px'}}>- {this.state.results[x].residents[y].assignment}: {this.state.results[x].residents[y].name} - {response}</div>)
                        })
                        .catch(err => {
                          console.log(err);
                        });
                      */




                        var colorRes = "black"
                        if (this.state.results.team[x].members[y].turnover) {
                          colorRes = "red"
                        }


                        residentsContent.push(<div style={{marginLeft: '10px', color: colorRes}}>- {this.state.results.team[x].members[y].name} * medHubID: ({this.state.results.team[x].members[y].userID})</div>)
                      }

                    content.push(<div>************************************************</div>)

                    content.push(teamHtml)
                    content.push(residentsContent)
                    content.push(<div>&nbsp;</div>)

                }


                for (var x in this.state.results.eval) {

                  var colorWard = "green"
                  if (this.state.results.eval[x].ward) {
                    colorWard = "blue"
                  }

                  content.push(<div style={{marginLeft: '10px', color: colorWard}}> Evalualtor: {this.state.results.eval[x].evaluator} * medHubID: ({this.state.results.team[x].members[y].userID})</div>)


                }


            return (
                <div className="container">
                  <div className="row justify-content-center">
                    <div className="col-md-8">
                      <h1 className="display-4 text-center">{todayDate}</h1>


{content}

<hr></hr>

<div>POST <b>evals/initiate</b></div>
<div>https://medhub.com/functions/api/evals/initiate</div>
<div>Delivers a new evaluation.</div>
<br></br>
<div>Input Variables</div><br></br>

<table border='1'>
  <tr>
    <td><b>Variable Name</b></td>
    <td nowrap='true'><b>Data Type</b></td>
    <td><b>Required</b></td>
    <td><b>Version</b></td>
    <td><b>Notes</b></td>
  </tr>
  <tr>
    <td>evaluationID</td>
    <td>integer</td>
    <td>Yes</td>
    <td>v1.15</td>
    <td>Use evals/forms to get a list of all active evaluations for a given program or course.</td>
  </tr>
  <tr>
    <td>evaluation_type</td>
    <td>integer</td>
    <td>Yes</td>
    <td>v1.15</td>
    <td>Use evals/types to get a list of all available evaluation types.</td>
  </tr>
  <tr>
    <td>evaluator_userID</td>
    <td>integer</td>
    <td>Yes</td>
    <td>v1.15</td>
    <td>Identifies the user that will recieve the evaluation.</td>
  </tr>
  <tr>
    <td>programID</td>
    <td>integer</td>
    <td>Yes</td>
    <td>v1.15</td>
    <td>Identifies the program delivering the evaluation. *Required if courseID not provided.</td>
  </tr>
  <tr>
    <td>courseID</td>
    <td>integer</td>
    <td>Yes</td>
    <td>v1.15</td>
    <td>Identifies the course delivering the evaluation. *Required if programID not provided.</td>
  </tr>
  <tr>
    <td>evaluatee_userID</td>
    <td>integer</td>
    <td>Yes</td>
    <td>v1.15</td>
    <td>*Required for all evaluation types where the target is a person.</td>
  </tr>
  <tr>
    <td>procedureID</td>
    <td>integer</td>
    <td>No</td>
    <td>v1.15</td>
    <td>*Required for all evaluations of procedures.</td>
  </tr>
  <tr>
    <td>lectureID</td>
    <td>integer</td>
    <td>No</td>
    <td>v1.15</td>
    <td>*Required for all evaluations of conferences or sessions</td>
  </tr>
  <tr>
    <td>globalserviceID</td>
    <td>integer</td>
    <td>No</td>
    <td>v1.15</td>
    <td>*Required if evaluation is of a service AND clinicnameID is not provided. Use schedules/services to get a list of service groups for a given program.</td>
  </tr>
  <tr>
    <td>clinicnameID</td>
    <td>integer</td>
    <td>No</td>
    <td>v1.15</td>
    <td>	*Required if evaluation is of a service AND globalserviceID is not provided. Use schedules/clinics to get a list of clinics defined for a given program or course.</td>
  </tr>
  <tr>
    <td>notify</td>
    <td>boolean</td>
    <td>No</td>
    <td>v1.15</td>
    <td>Pass TRUE to deliver an email notification to the evaluator.</td>
  </tr>
</table>
<br></br>
<div>Response Data</div><br></br>
<table border='1'>
  <tr>
    <td><b>Field Name</b></td>
    <td nowrap='true'><b>Description</b></td>
    <td><b>Data Type</b></td>
    <td><b>Version</b></td>
    <td><b>Notes</b></td>
  </tr>
  <tr>
    <td>responseID</td>
    <td>unique identifier for evaluation response</td>
    <td>integer</td>
    <td>v1.15</td>
    <td>Value "0" indicates a failed delivery.</td>
  </tr>
</table>



                    </div>
                  </div>
                </div>
            );
          }


  };

  export default Evalulation
